create extension if not exists pgcrypto;
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;

alter table public.notes add column if not exists created_at timestamptz not null default now();
alter table public.notes add column if not exists updated_at timestamptz not null default now();
alter table public.notes add column if not exists category text;
alter table public.notes add column if not exists tags text[] not null default '{}';

do $$ begin if not exists(select 1 from pg_trigger where tgname='notes_updated_at') then create trigger notes_updated_at before update on public.notes for each row execute function public.set_updated_at(); end if; end $$;

create table if not exists public.projects(id bigint generated by default as identity primary key,name text not null unique,description text,status text not null default 'Active',priority text not null default 'High',progress int not null default 0 check(progress between 0 and 100),notes text[] not null default '{}',next_actions text[] not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.tasks(id bigint generated by default as identity primary key,title text not null,description text,status text not null default 'Active',priority text not null default 'Medium',due_date date,completed boolean not null default false,project_id bigint references public.projects(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.goals(id bigint generated by default as identity primary key,title text not null,description text,status text not null default 'Active',priority text not null default 'High',progress int not null default 0 check(progress between 0 and 100),target_date date,project_id bigint references public.projects(id) on delete set null,milestones text[] not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.knowledge_items(id bigint generated by default as identity primary key,title text not null,content text not null,category text,source text,tags text[] not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.automations(id bigint generated by default as identity primary key,name text not null,description text,enabled boolean not null default false,schedule_text text,provider text not null default 'Jarvis',last_run_status text,next_run_at timestamptz,configuration_status text not null default 'Setup required',created_at timestamptz not null default now(),updated_at timestamptz not null default now());

create index if not exists tasks_due_date_idx on public.tasks(due_date);create index if not exists tasks_project_id_idx on public.tasks(project_id);create index if not exists goals_project_id_idx on public.goals(project_id);create index if not exists notes_updated_at_idx on public.notes(updated_at desc);create index if not exists knowledge_updated_at_idx on public.knowledge_items(updated_at desc);

do $$ declare t text; begin foreach t in array array['projects','tasks','goals','knowledge_items','automations'] loop execute format('drop trigger if exists %I_updated_at on public.%I',t,t);execute format('create trigger %I_updated_at before update on public.%I for each row execute function public.set_updated_at()',t,t); end loop; end $$;

alter table public.notes enable row level security;alter table public.projects enable row level security;alter table public.tasks enable row level security;alter table public.goals enable row level security;alter table public.knowledge_items enable row level security;alter table public.automations enable row level security;

do $$ declare t text; begin foreach t in array array['notes','projects','tasks','goals','knowledge_items','automations'] loop execute format('drop policy if exists "mvp_%I_select" on public.%I',t,t);execute format('drop policy if exists "mvp_%I_insert" on public.%I',t,t);execute format('drop policy if exists "mvp_%I_update" on public.%I',t,t);execute format('drop policy if exists "mvp_%I_delete" on public.%I',t,t);execute format('create policy "mvp_%I_select" on public.%I for select to anon using (true)',t,t);execute format('create policy "mvp_%I_insert" on public.%I for insert to anon with check (true)',t,t);execute format('create policy "mvp_%I_update" on public.%I for update to anon using (true) with check (true)',t,t);execute format('create policy "mvp_%I_delete" on public.%I for delete to anon using (true)',t,t); end loop; end $$;

